import{_ as I,o as D,c as T,ae as N}from"./chunks/framework.BGHOrOyn.js";const j="/gitbook-personnal-docs/assets/feature%20server.02tWNf7q.",g="data:application/octet-stream;base64,",L="data:application/octet-stream;base64,",A="/gitbook-personnal-docs/assets/feature%20live.Ccoj4GF9.",t="data:application/octet-stream;base64,",i="/gitbook-personnal-docs/assets/feature%20reports.CNPbusoY.",S=JSON.parse('{"title":"traccar.org","description":"https://www.traccar.org/download/","frontmatter":{"description":"https://www.traccar.org/download/"},"headers":[],"relativePath":"obd2/vehicle-tracking/traccar.org.md","filePath":"obd2/vehicle-tracking/traccar.org.md"}'),z={name:"obd2/vehicle-tracking/traccar.org.md"};function y(w,M,x,C,u,O){return D(),T("div",null,[...M[0]||(M[0]=[N('<h1 id="traccar-org" tabindex="-1">traccar.org <a class="header-anchor" href="#traccar-org" aria-label="Permalink to &quot;traccar.org&quot;">​</a></h1><p><img src="'+j+'" alt=""></p><p><strong>Server</strong></p><p>Traccar software provides high performance and stability on Windows, Linux or any other platform. The server can be self-hosted in the cloud or on-premise. We also provide a number of hosted options with professional support.</p><p><img src="'+g+'" alt=""></p><p><strong>Devices</strong></p><p>Traccar supports more protocols and device models than any other GPS tracking system on the market. You can select GPS trackers from a variety of vendors from low cost no-name models to high-end quality brands.</p><p><img src="'+L+'" alt=""></p><p><strong>Interface</strong></p><p>Traccar includes a modern fully-featured web interface with both desktop and mobile-friendly layouts. We also provide native mobile apps for Android and iOS platforms. In addition to that we have a set of apps enabling mobile devices to be used as GPS trackers.</p><p><img src="'+A+'" alt=""></p><p><strong>Live Tracking</strong></p><p>With Traccar you can view your GPS devices in real-time with no delay. We have various mapping options, including road maps and satellite imagery. The Server can handle a wide variety of sensors and additional information supplied by GPS units.</p><p><img src="'+t+'" alt=""></p><p><strong>Alerts</strong></p><p>Traccar software provides instant web notifications along with support for email and SMS. This allows for external alerting in cases of harsh driving behaviour like speeding, fuel and maintenance events, geo-fencing and many other types of alerts.</p><p><img src="'+i+'" alt=""></p><p><strong>Reports</strong></p><p>Traccar supports simple location history, trip, chart and summary reports. You can view data directly in the web or mobile app and also export and download an Excel file. History can also be projected on the map providing visual representation.</p>',19)])])}const o=I(z,[["render",y]]);export{S as __pageData,o as default};
